window.readWeb = async function(url) {
  const proxyUrl = '/api/proxy?url=' + encodeURIComponent('https://r.jina.ai/' + url);
  const r = await fetch(proxyUrl);
  return await r.text();
};
window.readWebJSON = async function(url) {
  const proxyUrl = '/api/proxy?url=' + encodeURIComponent(url);
  const r = await fetch(proxyUrl);
  return await r.json();
};
window.readProxy = async function(url) {
  const proxyUrl = '/api/proxy?url=' + encodeURIComponent(url);
  const r = await fetch(proxyUrl);
  return r;
};
